#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int dp[501][20001];
int n, m;
int edges[501][501];

void dfs(int node, int parent) {
    for (int i = 1; i <= m; i++) {
        dp[node][i] = 1;
    }
    for (int i = 1; i <= n; i++) {
        if (edges[node][i] == 1 && i != parent) {
            dfs(i, node);
            for (int j = 1; j <= m; j++) {
                for (int k = j; k <= m; k += j) {
                    dp[node][j] = (dp[node][j] + dp[i][k]) % MOD;
                }
            }
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        scanf("%d %d", &n, &m);
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                edges[i][j] = 0;
            }
        }
        for (int i = 1; i < n; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            edges[u][v] = edges[v][u] = 1;
        }
        dfs(1, -1);
        long long ans = 0;
        for (int i = 1; i <= m; i++) {
            ans = (ans + dp[1][i]) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

