#include <iostream>
#include <vector>
using namespace std;
#define MOD 1000000007

int dp[501][20001];
int n, m;
vector<int> edges[501];

void dfs(int node, int parent) {
    for (int i = 1; i <= m; i++) {
        dp[node][i] = 1;
    }
    for (int i = 0; i < edges[node].size(); i++) {
        int child = edges[node][i];
        if (child != parent) {
            dfs(child, node);
            for (int j = 1; j <= m; j++) {
                for (int k = j; k <= m; k += j) {
                    dp[node][j] = (dp[node][j] + dp[child][k]) % MOD;
                }
            }
        }
    }
}

int main() {
    int t;
    cin >> t;
    while (t--) {
        cin >> n >> m;
        for (int i = 1; i <= n; i++) {
            edges[i].clear();
        }
        for (int i = 1; i < n; i++) {
            int u, v;
            cin >> u >> v;
            edges[u].push_back(v);
            edges[v].push_back(u);
